import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  TextInput,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_KEY = '@authenticated';
const USER_CREDENTIALS_KEY = '@user_credentials';
const BIOMETRIC_ENABLED_KEY = '@biometric_enabled';

const rnBiometrics = new ReactNativeBiometrics();

const BiometricAuth = ({ onAuthSuccess }) => {
  const [loading, setLoading] = useState(true);
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState('');
  const [showPasswordFallback, setShowPasswordFallback] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    checkAuthStatus();
  }, []);

  const checkAuthStatus = async () => {
    try {
      const isAuthenticated = await AsyncStorage.getItem(AUTH_KEY);
      
      if (isAuthenticated === 'true') {
        onAuthSuccess();
        return;
      }

      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricsAvailable(available);
      setBiometricType(biometryType);

      const biometricEnabled = await AsyncStorage.getItem(BIOMETRIC_ENABLED_KEY);
      
      if (available && biometricEnabled === 'true') {
        setTimeout(() => {
          authenticateWithBiometrics();
        }, 500);
      } else {
        setShowPasswordFallback(true);
      }
    } catch (error) {
      console.error('Error checking auth status:', error);
      setShowPasswordFallback(true);
    } finally {
      setLoading(false);
    }
  };

  const authenticateWithBiometrics = async () => {
    try {
      const promptMessage = biometricType === 'FaceID' 
        ? 'Authenticate with Face ID' 
        : 'Authenticate with Fingerprint';

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Use Password',
      });

      if (success) {
        await setAuthenticatedStatus(true);
        onAuthSuccess();
      } else {
        setShowPasswordFallback(true);
      }
    } catch (error) {
      console.error('Biometric authentication error:', error);
      setShowPasswordFallback(true);
    }
  };

  const authenticateWithPassword = async () => {
    if (!username || !password) {
      Alert.alert('Error', 'Please enter username and password');
      return;
    }

    setLoading(true);
    try {
      const storedCredentials = await AsyncStorage.getItem(USER_CREDENTIALS_KEY);
      
      if (storedCredentials) {
        const { username: storedUsername, password: storedPassword } = JSON.parse(storedCredentials);
        
        if (username === storedUsername && password === storedPassword) {
          await setAuthenticatedStatus(true);
          onAuthSuccess();
        } else {
          Alert.alert('Error', 'Invalid credentials');
        }
      } else {
        await AsyncStorage.setItem(
          USER_CREDENTIALS_KEY,
          JSON.stringify({ username, password })
        );
        
        if (biometricsAvailable) {
          Alert.alert(
            'Enable Biometric Authentication',
            `Would you like to use ${biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'} for faster login?`,
            [
              {
                text: 'No',
                onPress: async () => {
                  await AsyncStorage.setItem(BIOMETRIC_ENABLED_KEY, 'false');
                  await setAuthenticatedStatus(true);
                  onAuthSuccess();
                },
              },
              {
                text: 'Yes',
                onPress: async () => {
                  await AsyncStorage.setItem(BIOMETRIC_ENABLED_KEY, 'true');
                  await setAuthenticatedStatus(true);
                  onAuthSuccess();
                },
              },
            ]
          );
        } else {
          await setAuthenticatedStatus(true);
          onAuthSuccess();
        }
      }
    } catch (error) {
      console.error('Password authentication error:', error);
      Alert.alert('Error', 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  const setAuthenticatedStatus = async (status) => {
    await AsyncStorage.setItem(AUTH_KEY, status ? 'true' : 'false');
  };

  const handleUseBiometrics = () => {
    setShowPasswordFallback(false);
    authenticateWithBiometrics();
  };

  if (loading && !showPasswordFallback) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Authenticating...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>
      
      {showPasswordFallback ? (
        <View style={styles.formContainer}>
          <TextInput
            style={styles.input}
            placeholder="Username"
            value={username}
            onChangeText={setUsername}
            autoCapitalize="none"
          />
          <TextInput
            style={styles.input}
            placeholder="Password"
            value={password}
            onChangeText={setPassword}
            secureTextEntry
            autoCapitalize="none"
          />
          <TouchableOpacity
            style={styles.button}
            onPress={authenticateWithPassword}
            disabled={loading}
          >
            {loading ? (
              <ActivityIndicator color="#fff" />
            ) : (
              <Text style={styles.buttonText}>Login</Text>
            )}
          </TouchableOpacity>

          {biometricsAvailable && (
            <TouchableOpacity
              style={styles.biometricButton}
              onPress={handleUseBiometrics}
            >
              <Text style={styles.biometricButtonText}>
                Use {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
              </Text>
            </TouchableOpacity>
          )}
        </View>
      ) : (
        <View style={styles.biometricContainer}>
          <Text style={styles.biometricMessage}>
            Authenticating with {biometricType === 'FaceID' ? 'Face ID' : 'Fingerprint'}
          </Text>
          <TouchableOpacity
            style={styles.fallbackButton}
            onPress={() => setShowPasswordFallback(true)}
          >
            <Text style={styles.fallbackButtonText}>Use Password Instead</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = async () => {
    await AsyncStorage.setItem(AUTH_KEY, 'false');
    setIsAuthenticated(false);
  };

  if (!isAuthenticated) {
    return <BiometricAuth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <View style={styles.homeContainer}>
      <Text style={styles.homeTitle}>Welcome!</Text>
      <Text style={styles.homeText}>You are authenticated</Text>
      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

